import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface RouteSplit {
  segment: string;
  time: string;
}

interface CurrentRun {
  pace: string;
  distance: number;
  elevationGain: number;
}

interface RunningStatsData {
  currentRun: CurrentRun;
  routeSplits: RouteSplit[];
}

export default function Widget() {
  const runningStatsData = response.data as RunningStatsData;
  const { currentRun, routeSplits } = runningStatsData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#2C2C2C' }} elevation={2}>
      <CardContent sx={{ p: 2.5, color: '#FFFFFF' }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: '#FF5722' }}>
              Current Run
            </Typography>
            <Typography variant="body1" sx={{ mb: 0.5 }}>
              Pace: {currentRun.pace}
            </Typography>
            <Typography variant="body1" sx={{ mb: 0.5 }}>
              Distance: {currentRun.distance} km
            </Typography>
            <Typography variant="body1">
              Elevation Gain: {currentRun.elevationGain} m
            </Typography>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: routeSplits.map((split) => parseFloat(split.time.replace(':', '.'))),
                color: '#FFC107',
                curve: 'linear',
                showMark: false,
              },
            ]}
            xAxis={[
              {
                data: routeSplits.map((split) => split.segment),
                hide: true,
              },
            ]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
